INSERT INTO public.photos VALUES (23160, 'Cuartel de Valdespartera 2003', 'Aspecto de las edificaciones del cuartel de Valdespartera en 2003, antes de su derribo ese mismo aâ”śâ–’o para iniciar la creaciâ”śâ”‚n de un nuevo barrio. Fuente: Heraldo de Aragâ”śâ”‚n.', 2003, 2003, 2003, 'Siglo XXI', 'CASABLANCA', 41.62008100, -0.93672100, '0101000020E6100000CD3E8F519EF9EDBF7CEF6FD05ECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32495841592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32495841592.webp', 'https://www.flickr.com/photos/zaragozaantigua/32495841592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23172, 'Centro comercial Lumier 2008', 'Recreaciâ”śâ”‚n infogrâ”śĂ­fica del exterior del centro comercial Lumier, en la calle Manhattan de Valdespartera. El proyecto fue presentado en 2008 y su inauguraciâ”śâ”‚n anunciada para aâ”śâ–’os sucesivos, hasta 2011. Habrâ”śÂˇa tenido una superficie de 74.000 metros cuadrados, 33.600 de superficie comercial, con un gran hipermercado, 94 tiendas y 5,9 millones de visitas anuales previstas. No se construyâ”śâ”‚. Fuente visual: www.a4arquitectos.es', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.62336000, -0.92545200, '0101000020E6100000C19140834D9DEDBF39D1AE42CACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33165525215.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33165525215.webp', 'https://www.flickr.com/photos/zaragozaantigua/33165525215/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23202, 'Calle El Greco 2010', 'Foto: Andrâ”śÂ®s Aguilar. Aspecto en enero de 2010 de la calle El Greco, en el barrio de Casablanca, tramo comprendido entre las calles de Encinacorba (a la espalda) y Marcelino â”śĂĽlvarez. Segâ”śâ•‘n sus vecinos, el plan para su asfaltado se remonta a 1970. Se produjo en 2015. Al fondo, fâ”śĂ­brica Ebroacero, en la calle Argualas. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASABLANCA', 41.62999500, -0.91328300, '0101000020E6100000C1C41F459D39EDBF5FD218ADA3D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32546422873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32546422873.webp', 'https://www.flickr.com/photos/zaragozaantigua/32546422873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23211, 'Cocheras Valdespartera 2010', 'Foto: Oliver Duch. Construcciâ”śâ”‚n de las cocheras de los tranvâ”śÂˇas, en la prolongaciâ”śâ”‚n de la avenida Gâ”śâ”‚mez Laguna 160. Al fondo, bloques de la calle de Volver a empezar. Fuente: Heraldo de Aragâ”śâ”‚n.', 2010, 2010, 2010, 'Siglo XXI', 'CASABLANCA', 41.62301000, -0.91454900, '0101000020E610000037DDB243FC43EDBF5D8AABCABECF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33553317661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33553317661.webp', 'https://www.flickr.com/photos/zaragozaantigua/33553317661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23219, 'Vâ”śÂˇa Ibâ”śÂ®rica 2015', 'Imagen capturada en la Vâ”śÂˇa Ibâ”śÂ®rica poco antes de llegar a la rotonda de conexiâ”śâ”‚n con la prolongaciâ”śâ”‚n de la avenida de Gâ”śâ”‚mez Laguna, y centrada en los edificios mudâ”śÂ®jares de mediados de los aâ”śâ–’os cincuenta del siglo XX que formaban parte de la subestaciâ”śâ”‚n de Elâ”śÂ®ctricas Reunidas de Zaragoza (actual Endesa) allâ”śÂˇ ubicada. El "Edificio Torreâ”śâ”‚n" de la imagen oculta otro edificio algo menos alto situado justo detrâ”śĂ­s de â”śÂ®l, levemente visible a la izquierda. A pesar de la solicitud de su catalogaciâ”śâ”‚n como interesante muestra de la arquitectura industrial de la segunda mitad del siglo XX en la ciudad, realizada en 2015 por Apudepa, en 2016 estos edificios fueron derribados. Fuese, y no hubo nada. En primer tâ”śÂ®rmino, moderno tendido tranviario de la lâ”śÂˇnea 1, Valdespartera-Parque Goya.', 2015, 2015, 2015, 'Siglo XXI', 'CASABLANCA', 41.62381900, -0.91244400, '0101000020E61000003ACE6DC2BD32EDBFCCCF0D4DD9CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50676947697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50676947697.webp', 'https://www.flickr.com/photos/zaragozaantigua/50676947697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23226, 'Recinto ferial de Valdespartera (virtual) 2019', 'Imagen virtual que recrea una vista nocturna y en altura del recinto ferial de Valdespartera, habilitado para esas funciones en 2006 para sustituir al veterano recinto instalado al final de la calle de Miguel Servet desde 1982, y que desde 2007 ejerce como tal.', 2019, 2019, 2019, 'Siglo XXI', 'CASABLANCA', 41.61966400, -0.93616300, '0101000020E61000003B35971B0CF5EDBF1841632651CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52494578958.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52494578958.webp', 'https://www.flickr.com/photos/zaragozaantigua/52494578958/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23264, 'Râ”śÂˇo Huerva 1922', 'Inâ”śÂ®dita imagen capturada a espaldas de la Almenara de Nâ”¬Â¬. Sâ”¬Â¬. del Pilar, donde el Canal Imperial de Aragâ”śâ”‚n desagua para reforzar el caudal del râ”śÂˇo Huerva (en primer tâ”śÂ®rmino) y de los riegos de las Adulas y Romareda. A la derecha, alturas de los montes de Torrero en la zona de los Pinares de Venecia, a cuyos pies va fluyendo el cauce del canal en descenso hasta llegar, a la izquierda, a Zaragoza, que se vislumbra tenuemente al fondo.', 1922, 1922, 1922, 'Anos 20', 'CASABLANCA', 41.62280500, -0.90432200, '0101000020E6100000BBB4E1B034F0ECBF84640113B8CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51400490057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51400490057.webp', 'https://www.flickr.com/photos/zaragozaantigua/51400490057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23355, 'Esclusas de Casablanca 1934', 'Autovâ”śÂˇa o automotor diesel tipo "Zaragoza", en un viaje de prueba por la lâ”śÂˇnea de ferrocarril de Cariâ”śâ–’ena. La imagen estâ”śĂ­ capturada desde el puente que da continuidad a la carretera de Zaragoza a Valencia, y centrada en el puente del ferrocarril con el fondo de las esclusas y central de Casablanca.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62817000, -0.90843200, '0101000020E6100000D57954FCDF11EDBF062AE3DF67D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15001990735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15001990735.webp', 'https://www.flickr.com/photos/zaragozaantigua/15001990735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23356, 'Fuente de los Incrâ”śÂ®dulos 1930', 'Sociedad Fotogrâ”śĂ­fica de Zaragoza/Sebastiâ”śĂ­n Gâ”śâ”‚mez Cortâ”śÂ®s, 1930. Este monumento fue levantado junto a las esclusas de Casablanca por orden de Ramâ”śâ”‚n Pignatelli, impulsor del Canal Imperial de Aragâ”śâ”‚n, en respuesta a las gentes que no confiaban en que pudiese llevarse a buen tâ”śÂ®rmino la magna obra hidrâ”śĂ­ulica. En su frontal, la inscripciâ”śâ”‚n: "Incredulorum convictioni et viatorum commodo. Anno MDCCLXXXVI", que traducimos: "Para convencimiento de los incrâ”śÂ®dulos y alivio de los caminantes. Aâ”śâ–’o 1786". NOTA: hemos volteado horizontalmente la imagen original, porque las cercanas parcelas que aparecen, quedaban a su derecha. Fuente visual: www.rsfz.es/', 1930, 1930, 1930, 'Anos 30', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15003804870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15003804870.webp', 'https://www.flickr.com/photos/zaragozaantigua/15003804870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23360, 'Molino de San Carlos aâ”śâ–’os 20', 'AHPZ. Gabriel Faci. Aâ”śâ–’os 20. "Molino de agua." La "Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad" fue constituida en 1893, tras la compra de la concesiâ”śâ”‚n del antiguo molino de San Carlos en Casablanca como generador de electricidad aprovechando el salto de agua, para suministrarla al alumbrado de la ciudad. En el antiguo molino se instalâ”śâ”‚ una nueva turbina de Averly, cuya fuerza serâ”śÂˇa transportada a la estaciâ”śâ”‚n central de la compaâ”śâ–’â”śÂˇa, sita en la calle San Miguel. En la imagen, molino de San Carlos turbinando agua. A la izquierda, las esclusas de Casablanca del Canal Imperial, en cuyo entorno habâ”śÂˇa un amplio conjunto de construcciones anexas que incluâ”śÂˇan puerto fluvial, noria con molino y batanes ademâ”śĂ­s de la Casa de San Carlos (la Casa Blanca, de la que mucho despuâ”śÂ®s tomarâ”śÂˇa su nombre el barrio), que se utilizâ”śâ”‚ como almacâ”śÂ®n y posada y que fue el lugar donde se firmaron las capitulaciones de Zaragoza de 1809, segâ”śâ•‘n informa una placa colocada en su fachada, porque Zaragoza no se rinde, pero sâ”śÂˇ capitula. Vamos, que nos ganaron.', 1920, 1920, 1929, 'Anos 20', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15482041181.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15482041181.webp', 'https://www.flickr.com/photos/zaragozaantigua/15482041181/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23361, 'Ojo del Canal 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" Imagen de "El Ojo del Canal", o puente-acueducto por medio del cual el Canal Imperial salva el râ”śÂˇo Huerva, tras haber pasado por las esclusas de Casablanca. En el momento de capturar la imagen, la almenara de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar estâ”śĂ­ derivando agua sobrante desde el Canal hacia el râ”śÂˇo Huerva. Este paraje era muy apreciado durante los meses de los calores, para refresco, alivio y regocijo ciudadano, y durante todo el aâ”śâ–’o para paseos, excursiones, aventuras. Era cuando el agua del Huerva era agua. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62253200, -0.90502300, '0101000020E6100000011764CBF2F5ECBF535BEA20AFCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16732611104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16732611104.webp', 'https://www.flickr.com/photos/zaragozaantigua/16732611104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23362, 'Esclusas de Casablanca 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El tâ”śÂˇtulo (la fuente visual asâ”śÂˇ lo cataloga) no se corresponde exactamente con la captura: se trata de una imagen parcial del complejo de las esclusas de Casablanca, donde se salva un importante desnivel del Canal Imperial, que "Elâ”śÂ®ctrica Reunidas" aprovechaba tambiâ”śÂ®n para una "fâ”śĂ­brica de electricidad" que allâ”śÂˇ tenâ”śÂˇa. Muy cerca quedaba la carretera de Zaragoza a Valencia, y la lâ”śÂˇnea de ferrocarril a Cariâ”śâ–’ena, con un andâ”śÂ®n junto a la Fuente de los Incrâ”śÂ®dulos. La carretera y el ferrocarril salvaban el Canal por medio de sendos puentes. Los edificios del fondo, al otro lado del Canal Imperial, se corresponden con el convento y colegio de los Padres Pasionistas de Casablanca, que en 1928 allâ”śÂˇ se habâ”śÂˇan instalado, tras adecuar las previas instalaciones de lo que habâ”śÂˇa sido una harinera, y luego dependencias militares. Entre diciembre de 1939 y junio de 1940, como forma de descongestionar la atestada câ”śĂ­rcel de Torrero, fue reconvertido en "Prisiâ”śâ”‚n Habilitada de Casablanca", hasta que fue desalojado por la oposiciâ”śâ”‚n de los PP. Pasionistas. En 1978 se culminâ”śâ”‚ su derribo. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17353076001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17353076001.webp', 'https://www.flickr.com/photos/zaragozaantigua/17353076001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23363, 'Fuente de los Incrâ”śÂ®dulos 1786', 'Fuente de los incrâ”śÂ®dulos, â”śâ”‚leo sobre lienzo, Joaquâ”śÂˇn Pallarâ”śÂ®s, 1928. Colecciâ”śâ”‚n Canal Imperial de Aragâ”śâ”‚n. Representaciâ”śâ”‚n, siglo y medio despuâ”śÂ®s, del momento en que Ramâ”śâ”‚n de Pignatelli, impulsor de las obras del Canal, inaugura junto a las esclusas de Casablanca la llamada Fuente de los Incrâ”śÂ®dulos, erigida en respuesta a quienes no confiaban en que esa infraestructura hidrâ”śĂ­ulica fuese construida.En su frontal, la inscripciâ”śâ”‚n: "Incredulorum convictioni et viatorum commodo. Anno MDCCLXXXVI", que traducimos: "Para convencimiento de los incrâ”śÂ®dulos y alivio de los caminantes. Aâ”śâ–’o 1786". Fuente: Ramâ”śâ”‚n Pignatelli y su â”śÂ®poca, Gobierno de Aragâ”śâ”‚n, 1993.', 1786, 1786, 1786, 'Siglo XIX', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19260108735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19260108735.webp', 'https://www.flickr.com/photos/zaragozaantigua/19260108735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23364, 'Molino de la Casa Blanca 1833', '"Molino de la Casa Blanca", litografâ”śÂˇa de Faramundo Blanchard. El molino harinero de San Carlos o de la Casa Blanca genera desde 1893 electricidad. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19304604860.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19304604860.webp', 'https://www.flickr.com/photos/zaragozaantigua/19304604860/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23366, 'Esclusas de Casablanca 1833', '"Esclusas de San Carlos", litografâ”śÂˇa de Faramundo Blanchard. Esclusas de Casablanca o de San Carlos, junto al Molino del mismo nombre en el Canal Imperial. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62833800, -0.90888200, '0101000020E6100000CE893DB48F15EDBFC26A2C616DD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19307474648.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19307474648.webp', 'https://www.flickr.com/photos/zaragozaantigua/19307474648/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23370, 'Almenara del Pilar 1833', '"La almenara Pilar y paso del Canal sobre el râ”śÂˇo Huerva", litografâ”śÂˇa de Faramundo Blanchard. Instalaciones de la almenara de Nuestra Seâ”śâ–’ora del Pilar (que sirve de desagâ”śâ•ťe del Canal al râ”śÂˇo Huerva) y del acueducto que lleva las aguas del Canal sobre las del Huerva, paraje conocido como Ojo del Canal. Permanecen en servicio. Fuente visual: "Memoria histâ”śâ”‚rica del Canal imperial de Aragon: noticia sobre las utilidades que produce, y esplicacion de lo que contienen las lâ”śĂ­minas que se publican", Madrid, 1833.', 1833, 1833, 1833, 'Siglo XIX', 'CASABLANCA', 41.62253200, -0.90502300, '0101000020E6100000011764CBF2F5ECBF535BEA20AFCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19486016262.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19486016262.webp', 'https://www.flickr.com/photos/zaragozaantigua/19486016262/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23378, 'Puente Caminreal - Canal Imperial 1933', 'Imagen del nuevo puente construido sobre el Canal Imperial, para salvar el paso de las vâ”śÂˇas del ferrocarril de Caminreal a Zaragoza. Hacia la derecha las vâ”śÂˇas conducen a la novâ”śÂˇsima estaciâ”śâ”‚n de Caminreal, en la Almozara, pasando por Miralbueno el Viejo, la carretera de Madrid a Francia por La Junquera, Val del Fierro, Miralbueno, y la carretera de Logroâ”śâ–’o. A la espalda del fotâ”śâ”‚grafo quedarâ”śÂˇan los depâ”śâ”‚sitos de agua de Casablanca. Hacia la izquierda, todo recto hasta Valdespartera, donde la vâ”śÂˇa gira para ponerse paralela a la carretera de Zaragoza a Teruel. Fuente visual: &quot;Ingenierâ”śÂˇa y Construcciâ”śâ”‚n&quot; (Madrid).', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.63594000, -0.92283000, '0101000020E6100000D690B8C7D287EDBFEF1B5F7B66D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21722907949.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21722907949.webp', 'https://www.flickr.com/photos/zaragozaantigua/21722907949/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23382, 'Râ”śÂˇo Huerva 1860', '"Almenara de Nuestra Seâ”śâ–’ora del Pilar y paso del Canal Imperial sobre el râ”śÂˇo Huerva." Fotâ”śâ”‚grafo: Mariano Jâ”śâ•‘dez y Ortiz, Esta esplâ”śÂ®ndida fotografâ”śÂˇa, de una calidad sobresaliente, captura el paraje denominado "el Ojo del Canal" (de 13 metros de anchura y 35 metros de altura), por medio del cual el Canal salva mediante un acueducto-puente el cauce del râ”śÂˇo Huerva, y cayendo por gravedad en la Almenara del Pilar, desagua al râ”śÂˇo caudales de agua, y ayuda al vaciado del Canal. Unas decenas de metros a la derecha, del Canal Imperial deriva la acequia de la "Romarera", luego "Romareda". Fuente visual: Museo del Prado.', 1860, 1860, 1860, 'Siglo XIX', 'CASABLANCA', 41.62225100, -0.90475700, '0101000020E61000006077BAF3C4F3ECBF9F73B7EBA5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23747473619.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23747473619.webp', 'https://www.flickr.com/photos/zaragozaantigua/23747473619/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23383, 'Ojo del Canal 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" Imagen de "el Ojo del Canal", o puente-acueducto por medio del cual el Canal Imperial salva el râ”śÂˇo Huerva, tras haber pasado por las esclusas de Casablanca (a la izquierda). La imagen se ha capturado desde la orilla del Huerva, cuando este râ”śÂˇo era aâ”śâ•‘n una corriente fluvial natural en torno a la cual habâ”śÂˇa un buen puâ”śâ–’ado de ubicaciones donde la gente pescaba, se baâ”śâ–’aba, hacâ”śÂˇan paseos... y todo sin tener que ponerles etiquetas de "corredor verde", "andador", u otras postmodernas etiquetas. Por encima, el Canal continâ”śâ•‘a aâ”śÂ®reo hacia la derecha, hacia el parque de Buenavista. Fuente visual: Fotografâ”śÂˇa de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASABLANCA', 41.62206100, -0.90508300, '0101000020E6100000554CA59F70F6ECBFFC8EE1B19FCF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26794344485.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26794344485.webp', 'https://www.flickr.com/photos/zaragozaantigua/26794344485/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23384, 'Carretera de Valencia c.1925', 'Puente de la carretera de Zaragoza a Valencia, a su paso sobre el Canal Imperial de Aragâ”śâ”‚n. Fue inaugurado en 1786. Al fondo, las esclusas de Casablanca. Fuente visual: Foto: Josep Gaspar i Serra, Arxiu Generalitat de Catalunya.', 1925, 1925, 1925, 'Anos 20', 'CASABLANCA', 41.62807900, -0.90826200, '0101000020E6100000BB6246787B10EDBFF62686E464D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27585999193.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27585999193.webp', 'https://www.flickr.com/photos/zaragozaantigua/27585999193/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23391, 'Canal Imperial 2008', 'Vista aâ”śÂ®rea de las obras de acondicionamiento del Canal Imperial de Aragâ”śâ”‚n en 2008. Se trata del tramo en el que â”śÂ®ste pasa sobre el râ”śÂˇo Huerva, junto a la almenara del Pilar. Fuente: Ayuntamiento de Zaragoza.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.62287200, -0.90552200, '0101000020E610000055DFF94509FAECBF0CCC0A45BACF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33125109391.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33125109391.webp', 'https://www.flickr.com/photos/zaragozaantigua/33125109391/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23396, 'Canal Imperial 1934', 'Autovâ”śÂˇa o automotor diesel tipo "Zaragoza" en un viaje de prueba por la lâ”śÂˇnea del clausurado ferrocarril de Cariâ”śâ–’ena. La imagen estâ”śĂ­ capturada desde el puente que da continuidad a la carretera de Zaragoza a Valencia, y centrada en el ferroviario puente tendido sobre el cauce del Canal Imperial de Aragâ”śâ”‚n junto a las esclusas y la fâ”śĂ­brica de electricidad de Casablanca de Elâ”śÂ®ctricas Reunidas de Zaragoza. A la derecha y fuera de plano quedaba el convento y colegio de los Padres Pasionistas de Casablanca. Tras el automotor, arbolado panorama sobre el que emergen al fondo los montes de Valdespartera y la altura de la ermita de Santa Bâ”śĂ­rbara.', 1934, 1934, 1934, 'Anos 30', 'CASABLANCA', 41.62820200, -0.90846400, '0101000020E6100000ADFC32182312EDBF12A452EC68D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49621359021.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49621359021.webp', 'https://www.flickr.com/photos/zaragozaantigua/49621359021/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23400, 'Valdespartera 1912', 'Foto: Lorenzo Almarza. ''"Un monoplano militar en Valdespartera". Varios de los primeros aviones que maniobraron en la ciudad fueron pilotados por militares franceses como Teixier y Garnier, que en el marco de unas "Fiestas de la Aviaciâ”śâ”‚n" celebradas en el Campo de Valdespartera el 6 de octubre de 1912, volaron los aparatos por el cielo sobre Zaragoza. Fuente visual: Archivo Diputaciâ”śâ”‚n Provincial de Huesca.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14942623399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14942623399.webp', 'https://www.flickr.com/photos/zaragozaantigua/14942623399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23402, 'Valdespartera 1911', 'Imagen capturada en el aerâ”śâ”‚dromo de Valdespartera durante la semana de aviaciâ”śâ”‚n de abril de 1911.', 1911, 1911, 1911, 'Anos 10', 'CASABLANCA', 41.62469400, -0.93180800, '0101000020E61000005ED6C4025FD1EDBFF30016F9F5CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15206485345.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15206485345.webp', 'https://www.flickr.com/photos/zaragozaantigua/15206485345/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23404, 'Valdespartera 1912', 'Fotografâ”śÂˇa aâ”śÂ®rea tomada en el aerâ”śâ”‚dromo de Valdespartera de Zaragoza. Fuente: Fotografâ”śÂˇa de Aurelio Grasa publicada en la pâ”śĂ­gina 50 del catâ”śĂ­logo "Aurelio Grasa reportero grâ”śĂ­fico 1910-1917", RSFZ, Galerâ”śÂˇa Costa,3. Zaragoza 2000. www.barbozagrasa.es/primera-foto-aerea-de-aurelio-grasa-e...', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19264829971.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19264829971.webp', 'https://www.flickr.com/photos/zaragozaantigua/19264829971/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23409, 'Valdespartera 2002', 'Plano mediante infografâ”śÂˇa del proyecto del barrio de Valdespartera de Zaragoza en 2002. En 2001, las 243 hectâ”śĂ­reas del Acuartelamiento de Valdespartera fueron cedidas por el Ministerio de Defensa al Ayuntamiento de Zaragoza, para construir un barrio, aprobado en pleno en noviembre de 2002, enmarcado en las polâ”śÂˇticas de expansiâ”śâ”‚n urbanâ”śÂˇstica salvaje propias de la â”śÂ®poca. El proyecto original incluâ”śÂˇa como atractivo principal el nuevo campo de fâ”śâ•‘tbol de la ciudad (zona gris a la derecha), que pronto fue desestimado y borrado de las representaciones grâ”śĂ­ficas. No asâ”śÂˇ la pista de esquâ”śÂˇ cubierta junto a un anfiteatro y una pista de hielo (arriba a la izquierda, hoy recinto ferial). Valdespartera se sitâ”śâ•‘a entre el Cuarto Cinturâ”śâ”‚n (izquierda), Montecanal y la avenida Gâ”śâ”‚mez Laguna (derecha), y la carretera de Valencia (abajo). Estâ”śĂ­ atravesado de norte a sur por la autovâ”śÂˇa Mudâ”śÂ®jar (en la imagen, de izquierda a derecha). Fuente: www.valdespartera.es/', 2002, 2002, 2002, 'Siglo XXI', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22001742031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22001742031.webp', 'https://www.flickr.com/photos/zaragozaantigua/22001742031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23410, 'Valdespartera 2002', 'Zaragoza. Plan parcial del sector 89/4 Valdespartera. Ramâ”śâ”‚n Betrâ”śĂ­n. Ayuntamiento de Zaragoza, 2002. En 2001, las 243 hectâ”śĂ­reas del Acuartelamiento de Valdespartera fueron cedidas por el Ministerio de Defensa al Ayuntamiento de Zaragoza, para construir un barrio, aprobado en pleno en noviembre de 2002, enmarcado en las polâ”śÂˇticas de expansiâ”śâ”‚n urbanâ”śÂˇstica salvaje propias de la â”śÂ®poca. El proyecto original incluâ”śÂˇa como atractivo principal el nuevo campo de fâ”śâ•‘tbol de la ciudad (arriba a la derecha), que pronto fue desestimado y borrado de las representaciones grâ”śĂ­ficas (ver www.flickr.com/photos/zaragozaantigua/22001742031). No asâ”śÂˇ la pista de esquâ”śÂˇ cubierta junto a un anfiteatro y una pista de hielo (abajo, hoy recinto ferial). Valdespartera se sitâ”śâ•‘a entre el Cuarto Cinturâ”śâ”‚n (abajo), Montecanal y la avenida Gâ”śâ”‚mez Laguna (arriba), y la carretera de Valencia (derecha). Estâ”śĂ­ atravesado de norte a sur por la autovâ”śÂˇa Mudâ”śÂ®jar. Fuente: Zaragoza 1908-2008. Colegio Oficial de Arquitectos de Aragâ”śâ”‚n, 2009.', 2002, 2002, 2002, 'Siglo XXI', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22340119396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22340119396.webp', 'https://www.flickr.com/photos/zaragozaantigua/22340119396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23412, 'Fuente de la Junquera 2008', 'Otra de las promesas de la Expo 2008 que quedâ”śâ”‚ sin cumplir fue la "integraciâ”śâ”‚n final" del râ”śÂˇo Huerva en la ciudad. "Tres nuevas pasarelas, y una red de andadores que hacen accesibles sus riberas", un poco de magia, abracadabra, y ya estâ”śĂ­. Esta era la visiâ”śâ”‚n del asunto que transmitiâ”śâ”‚ la Confederaciâ”śâ”‚n Hidrogrâ”śĂ­fica del Ebro mediante los medios creadores de opiniâ”śâ”‚n para las masas. En el caso que ocupa la imagen, se trataba del tramo del râ”śÂˇo Huerva donde el nuevo parque de la Fuente de la Junquera, un muy interesante paraje fluvial (quâ”śÂ® recuerdos), sâ”śâ”‚lo que a unos cinco kilâ”śâ”‚metros del "centro" de la ciudad consolidada. Los ciudadanos que lo queremos disfrutar, tenemos un agradable y natural paseo hasta â”śÂ®l, a no ser que se emplee algâ”śâ•‘n vehâ”śÂˇculo motorizado. No hay grandes aglomeraciones, parece ser. Como quiera que sea la cosa, este nuevo parque, de dos hectâ”śĂ­reas de extensiâ”śâ”‚n, incluâ”śÂˇa una pasarela de madera de 13 metros de largo, 7000 metros cuadrados de câ”śÂ®sped en rollos, 1000 metros de riego por goteo, 2500 metros de caminos, ademâ”śĂ­s de numerosos â”śĂ­rboles y especies mediterrâ”śĂ­neas. En la imagen, aspecto parcial del nuevo parque, con el râ”śÂˇo Huerva a la derecha, la pasarela, los distintos niveles de terraza, los rollos de câ”śÂ®sped, y las nuevas especies plantadas. Al fondo, la urbanizaciâ”śâ”‚n Fuente de la Junquera y sus rojas techumbres, y de telâ”śâ”‚n escâ”śÂ®nico, tras la carretera de Valencia, los megabloques en construcciâ”śâ”‚n de Valdespartera, correspondientes al entorno de la plaza de "Cleopatra", y las calles "El maquinista de La General", "Los pâ”śĂ­jaros", y "La Reina de â”śĂĽfrica". Lo que es propiamente la Fuente de la Junquera, la pobre queda a unos pocos metros hacia la derecha, fuera de plano. Fuente visual: â”śĂĽlvaro Calvo, para Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.61479400, -0.91540400, '0101000020E61000002B155454FD4AEDBF76E3DD91B1CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24483199260.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24483199260.webp', 'https://www.flickr.com/photos/zaragozaantigua/24483199260/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23414, 'CAE 1895', 'Imagen del antiguo molino de San Carlos en Casablanca, desde 1893 de la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE), turbinando agua del Canal Imperial para generar electricidad con destino al suministro urbano. A finales de 1904 esta empresa se fusionâ”śâ”‚ con la Electra Peral Zaragozana, y con Fuerzas Motrices del Gâ”śĂ­llego, un paso para la gran integraciâ”śâ”‚n de 1911 que dio como resultado Elâ”śÂ®ctricas Reunidas de Zaragoza. En la imagen, las dos turbinas a pleno funcionamiento. Fuente visual: Foto Estudio Coyne, AHPZ.', 1895, 1895, 1895, 'Siglo XIX', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30857496524.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30857496524.webp', 'https://www.flickr.com/photos/zaragozaantigua/30857496524/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23415, 'Câ”śĂ­mping 2008', 'Vista aâ”śÂ®rea centrada en el Câ”śĂ­mping Municipal "Ciudad de Zaragoza", inaugurado en 2008 en la finca El Gracijo, en el lâ”śÂˇmite del barrio de Casablanca junto al Canal Imperial. Arriba a la derecha, Valdefierro. Abajo a la derecha, tras la calle San Juan Bautista de la Salle, Rosales del Canal. Fuente: eszaragoza.blogspot.com', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63864400, -0.94186700, '0101000020E6100000EECF4543C623EEBFB0E42A16BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30913077652.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30913077652.webp', 'https://www.flickr.com/photos/zaragozaantigua/30913077652/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23417, 'Casa Blanca c.1900', 'Imagen del complejo dieciochesco con las esclusas (izquierda) y antiguo molino de San Carlos en Casablanca (derecha), instalaciâ”śâ”‚n que la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE), y mediante el turbinado de agua del Canal Imperial, utilizaba para generar electricidad con destino al suministro urbano. En primer tâ”śÂ®rmino, el trazado del primitivo ferrocarril de vâ”śÂˇa mâ”śÂ®trica que unâ”śÂˇa desde 1887 Cariâ”śâ–’ena con Zaragoza, y que en 1913 pasarâ”śÂˇa a formar parte del Ferrocarril Central de Aragâ”śâ”‚n. En este punto se ubicaba el apeadero de Casablanca.', 1900, 1900, 1900, 'Anos 1900', 'CASABLANCA', 41.62863500, -0.90876400, '0101000020E61000005307793D9814EDBF7C0F971C77D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31575799160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31575799160.webp', 'https://www.flickr.com/photos/zaragozaantigua/31575799160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23418, 'El Gracijo 2007', 'En 2004, el Ayuntamiento de Zaragoza permutâ”śâ”‚ los terrenos de la finca El Gracijo por los del antiguo câ”śĂ­mping de la ciudad (con derecho a elevar allâ”śÂˇ 72 viviendas), para construir en aquella finca el nuevo câ”śĂ­mping, inaugurado en 2008. La familia Escoriaza utilizaba como entrada a su villa de recreo la original puerta de rejerâ”śÂˇa del Gran Hotel, construido en 1929 y reformado en 1981, tras su compra por Arturo Beltrâ”śĂ­n. Pese a que estaba previsto que esta puerta permaneciese en el nuevo câ”śĂ­mping, en 2010 se trasladâ”śâ”‚ al Pabellâ”śâ”‚n de Ceremonias del Parque del Agua Luis Buâ”śâ–’uel. En la foto, obras de acondicionamiento en agosto de 2007 de la finca El Gracijo para su conversiâ”śâ”‚n en nuevo câ”śĂ­mping, con la puerta del Gran Hotel en el centro. La ubicaciâ”śâ”‚n es en la calle San Juan Bautista de la Salle s/n, en el lâ”śÂˇmite del barrio de Casablanca, junto al Canal Imperial y cerca de Valdefierro. Fuente visual: Heraldo de Aragâ”śâ”‚n.', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.63864400, -0.94186700, '0101000020E6100000EECF4543C623EEBFB0E42A16BFD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31628700266.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31628700266.webp', 'https://www.flickr.com/photos/zaragozaantigua/31628700266/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23420, 'Pre San Juan Bautista de la Salle 2008', 'Foto: Juan Carlos Arcos. Construcciâ”śâ”‚n del vial que serâ”śĂ­ denominado calle de San Juan Bautista de la Salle, entre los barrios de Valdefierro (izquierda) y Montecanal (derecha). Unirâ”śĂ­ la carretera de Madrid (luego avenida de Manuel Rodrâ”śÂˇguez Ayuso) con la avenida de Gâ”śâ”‚mez Laguna (al fondo). Sobre el horizonte, la torre de la Cooperativa de Auto Taxi y el centro de formaciâ”śâ”‚n profesional La Salle Santo â”śĂĽngel. Esta infraestructura serâ”śĂ­ inaugurada en diciembre de 2008 con la denominaciâ”śâ”‚n provisional de vâ”śÂˇa Parque del Canal. Fuente: Heraldo de Aragâ”śâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CASABLANCA', 41.63267800, -0.93066600, '0101000020E6100000ECF82F1004C8EDBF0873BB97FBD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31990889483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31990889483.webp', 'https://www.flickr.com/photos/zaragozaantigua/31990889483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23422, 'Valdespartera 1912', 'Imagen capturada durante las "fiestas de aviaciâ”śâ”‚n" incluidas como profana actividad en las fiestas del Pilar de ese aâ”śâ–’o. Los pilotos franceses Teixier y Garnier, pioneros de la aviaciâ”śâ”‚n, realizaron magnâ”śÂˇficos vuelos de exhibiciâ”śâ”‚n en el aerâ”śâ”‚dromo de Valdespartera, alcanzando alturas vertiginosas de hasta 1000 metros, ante la entregada parroquia venida a estos esteparios parajes del suroeste de la ciudad. Al atardecer, y sobre el fondo de los escarpados vales, aterrizaje de uno de los aparatos utilizados, un monoplano Blâ”śÂ®riot modelo XI pilotado por Lâ”śÂ®once Garnier que, ademâ”śĂ­s de protagonizar hazaâ”śâ–’as civiles como la de sobrevolar por primera vez los Pirineos, ese mismo aâ”śâ–’o estaba siendo utilizado como arma de guerra por el reino de Italia en su invasiâ”śâ”‚n colonialista de la Libia otomana, operaciâ”śâ”‚n que los agresores denominaron "pacificaciâ”śâ”‚n de Libia". Fuente visual: foto Luis Gandâ”śâ•‘ Mercadal, en patrimoniocultural.unizar.es/node/3344', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34571695595.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34571695595.webp', 'https://www.flickr.com/photos/zaragozaantigua/34571695595/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23423, 'Apeadero de Casablanca 1912', 'Imagen capturada desde el camino que en paralelo al Canal Imperial ascendâ”śÂˇa hasta el entorno de la esclusas de Casablanca. A la izquierda, el puente por el que cruza la carretera de Zaragoza a Valencia. Al fondo, a la izquierda, el camino de sirga y el convento de los PP. Pasionistas. De fondo, el antiguo molino de San Carlos que desde 1893 turbinaba agua del Canal como central de electricidad, en ese momento para la reciente empresa Elâ”śÂ®ctricas Reunidas de Zaragoza. A la derecha, el apeadero de Casablanca del ferrocarril de vâ”śÂˇa estrecha de Zaragoza a Cariâ”śâ–’ena. Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal. Una crâ”śâ”‚nica visual 1910-1930.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.62806000, -0.90801200, '0101000020E610000086048C2E6F0EEDBF7FF6234564D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35966619934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35966619934.webp', 'https://www.flickr.com/photos/zaragozaantigua/35966619934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23424, 'Valdespartera 1912', 'Imagen capturada durante las "fiestas de aviaciâ”śâ”‚n" que fueron incluidas en el programa de actos de las locales fiestas del mes de octubre, en la que los pilotos franceses pioneros de la aviaciâ”śâ”‚n Teixier y Garnier realizaron magnâ”śÂˇficos vuelos de exhibiciâ”śâ”‚n en el aerâ”śâ”‚dromo de Valdespartera. En la imagen, instalaciones del aerâ”śâ”‚dromo en los esteparios parajes del suroeste de la ciudad, y uno de los aparatos utilizados, un monoplano Blâ”śÂ®riot modelo XI pilotado por Lâ”śÂ®once Garnier, rodeado de curiosos y pâ”śâ•‘blico asistente a las exhibiciones. Fuente visual: El fotâ”śâ”‚grafo Luis Gandâ”śâ•‘ Mercadal. Una crâ”śâ”‚nica visual 1910-1930.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/37246219881.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/37246219881.webp', 'https://www.flickr.com/photos/zaragozaantigua/37246219881/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23425, 'Valdespartera 2007', 'Vista aâ”śÂ®rea parcial de la construcciâ”śâ”‚n del barrio de Valdespartera en 2007. A la derecha, la autovâ”śÂˇa a Valencia y el râ”śÂˇo Huerva. Abajo, el Cuarto Cinturâ”śâ”‚n de ronda. Fuente: www.valdespartera.es', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39795780815.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39795780815.webp', 'https://www.flickr.com/photos/zaragozaantigua/39795780815/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23426, 'Valdespartera 2007', 'Vista aâ”śÂ®rea del suroeste de Zaragoza, con el barrio de Valdespartera en construcciâ”śâ”‚n en el centro. Abajo, urbanizaciâ”śâ”‚n Fuente de La Junquera. Arriba, Montecanal, el futuro Arcosur, la Plataforma Logâ”śÂˇstica PLAZA y el aeropuerto. Fuente: www.valdespartera.es', 2007, 2007, 2007, 'Siglo XXI', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40690939811.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40690939811.webp', 'https://www.flickr.com/photos/zaragozaantigua/40690939811/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23429, 'Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad 1895', 'Imagen capturada en el interior del antiguo molino de San Carlos en Casablanca, cuya concesiâ”śâ”‚n habâ”śÂˇa comprado en 1893 la reciâ”śÂ®n constituida Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad para producir electricidad de orâ”śÂˇgen hidrâ”śĂ­ulico y suministrarla al alumbrado nocturno de Zaragoza. En la imagen, tres operarios posan alrededor del alternador monofâ”śĂ­sico Brown Boveri accionado en la estancia de la derecha por una turbina Fountain-Girard. Desde este alternador se transportaba luego la fuerza producida a la estaciâ”śâ”‚n subsidiaria de la compaâ”śâ–’â”śÂˇa sita en la calle de San Miguel, en la manzana entre las calles de Porcell y de Blancas. Allâ”śÂˇ, dos dinamos eran accionadas por esta energâ”śÂˇa y durante la noche proporcionaban corriente continua a la red elâ”śÂ®ctrica. En 1904 esta compaâ”śâ–’â”śÂˇa, junto con la Electra Peral y Fuerzas Motrices del Gâ”śĂ­llego, se agruparon y formaron Elâ”śÂ®ctricas Reunidas de Zaragoza.', 1895, 1895, 1895, 'Siglo XIX', 'CASABLANCA', 41.62886800, -0.90871000, '0101000020E6100000878A71FE2614EDBF1EC022BF7ED04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50294596893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50294596893.webp', 'https://www.flickr.com/photos/zaragozaantigua/50294596893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23430, 'Esclusas Casablanca c.1900', 'Imagen capturada con el fondo del antiguo molino de San Carlos en Casablanca utilizado por la Compaâ”śâ–’â”śÂˇa Aragonesa de Electricidad (CAE) para turbinar agua del Canal Imperial y generar electricidad con destino al suministro urbano. En primer tâ”śÂ®rmino, desde donde se ha tirado la fotografâ”śÂˇa, estaba el trazado del primitivo ferrocarril de vâ”śÂˇa mâ”śÂ®trica que unâ”śÂˇa desde 1887 Cariâ”śâ–’ena con Zaragoza. A la izquierda y fuera de plano, las esclusas de Casablanca.', 1900, 1900, 1900, 'Anos 1900', 'CASABLANCA', 41.62844400, -0.90811100, '0101000020E61000005169C4CC3E0FEDBF08AF5DDA70D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50941523413.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50941523413.webp', 'https://www.flickr.com/photos/zaragozaantigua/50941523413/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23432, 'Leoncio Garnier 1912', 'El francâ”śÂ®s Leoncio Garnier estaba establecido desde 1905 en San Sebastiâ”śĂ­n, donde regentaba un garaje de autos. Cuando poco despuâ”śÂ®s comenzâ”śâ”‚ la eclosiâ”śâ”‚n de la aviaciâ”śâ”‚n, Leoncio se volcâ”śâ”‚ en ella con el espâ”śÂˇritu de los locos pioneros, construyâ”śÂ®ndose un aparato monoplano volador que serâ”śÂˇa el primero de sus caracterâ”śÂˇsticas realizado en Espaâ”śâ–’a. Desde entonces, y aunque mantenâ”śÂˇa su negocio del garaje, se dedicâ”śâ”‚ completamente a volar en las denominadas "fiestas de la aviaciâ”śâ”‚n" que proliferaron como un innovador componente de la programaciâ”śâ”‚n festiva en muchas ciudades espaâ”śâ–’olas. De esta forma, en 1912 Leoncio ya llevaba realizados solo ese aâ”śâ–’o 209 vuelos a lo largo y ancho de la geografâ”śÂˇa peninsular, cuando en octubre recayâ”śâ”‚ en Zaragoza, contratado para volar durante las fiestas del Pilar en el campo de Valdespartera. Lo hizo con el aeroplano de la imagen: un monoplano Bleriot tipo XI con motor de 50 caballos de fuerza, capaz de llevar a un piloto que no sobrepasara los sesenta kilos de peso... En uno de los vuelos estuvo en el aire diecisâ”śÂ®is minutos, recorriendo treinta kilâ”śâ”‚metros a una altura mâ”śĂ­xima de doscientos metros. El pâ”śâ•‘blico llegado desde la ciudad y las primeras autoridades de la misma le felicitaron por la hazaâ”śâ–’a. Dos aâ”śâ–’os mâ”śĂ­s tarde y hasta 1918 Leoncio combatiâ”śâ”‚ como Lâ”śÂ®once bajo la bandera francesa en la Gran Guerra contra Alemania, sobreviviendo a este terrible conflicto.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61982400, -0.92727100, '0101000020E610000056EF703B34ACEDBF51A3906456CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53457709300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53457709300.webp', 'https://www.flickr.com/photos/zaragozaantigua/53457709300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23433, 'Valdespartera 1912', 'Fotograma de un breve e interesante reportaje dedicado a las fiestas de la Aviaciâ”śâ”‚n incluidas en el programa de las Fiestas del Pilar de 1912, cuando los pilotos franceses Henri Tixier y Lâ”śÂ®once Garnier fueron contratados para realizar varias demostraciones aâ”śÂ®reas en el improvisado aerâ”śâ”‚dromo de Valdespartera. Aquâ”śÂˇ posan ambos y el mecâ”śĂ­nico de Tixier ante un monoplano Blâ”śÂ®riot-XI utilizado por â”śÂ®ste para la ocasiâ”śâ”‚n, en la provisional estructura construida para albergarlo.', 1912, 1912, 1912, 'Anos 10', 'CASABLANCA', 41.61640400, -0.92868800, '0101000020E6100000360186E5CFB7EDBFD28F8653E6CE4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54656086264.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54656086264.webp', 'https://www.flickr.com/photos/zaragozaantigua/54656086264/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23722, 'Santa Inâ”śÂ®s 1965', 'Imagen desde las alturas para contemplar el moderno monasterio de Santa Inâ”śÂ®s de las Madres Dominicas contemplativas de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, que en 1949 traspasaron a las Madres Dominicas de la Anunciata su convento-colegio de la calle de Santa Inâ”śÂ®s, y se vinieron a recaer a la despejada ribera del Canal Imperial, cerca de la carretera de enlaces. A este complejo conventual, construido entre 1961-63 segâ”śâ•‘n diseâ”śâ–’o de fray Francisco Coello de Portugal, se accedâ”śÂˇa principalmente desde el antiguo camino de la Mosquetera (abajo, a la izquierda), y confrontaba, a la izquierda, con las instalaciones de la planta embotelladora Aragonesa de Bebidas Gaseosas (ARBEGA), S.A. Al otro lado del Canal, a la derecha, fuera de plano, el humedal de los depâ”śâ”‚sitos de agua de Casablanca. Fuente visual: Arxiu Nacional de Catalunya', 1965, 1965, 1965, 'Anos 60', 'CASABLANCA', 41.63460300, -0.91335500, '0101000020E6100000276BD443343AEDBFC478CDAB3AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31821087335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31821087335.webp', 'https://www.flickr.com/photos/zaragozaantigua/31821087335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23993, 'Valdespartera 1958', 'Rodaje del filme "Salomâ”śâ”‚n y la Reina de Saba" en los esteparios montes de Valdespartera, considerados por la MGM muy parecidos a los parajes de la penâ”śÂˇnsula del Sinaâ”śÂˇ. En una pausa, los actores principales (Tyrone Power, antes de su ataque al corazâ”śâ”‚n, Gina Lollobrigida, y George Sanders) estâ”śĂ­n comentando alguna cuestiâ”śâ”‚n relacionada con la prâ”śâ”‚xima escena. Pero con la incorporaciâ”śâ”‚n de la maquilladora, y el imprudente conductor del carro, estâ”śĂ­n a punto de constituirse en una reuniâ”śâ”‚n pâ”śâ•‘blica que supera el nâ”śâ•‘mero de tres personas, y como no tienen permiso previo de la Autoridad, un funcionario de la Guardia Civil atento centinela por si recibe orden de la Superioridad para intervenir. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1958, 1958, 1958, 'Anos 50', 'CASABLANCA', 41.62413000, -0.93065700, '0101000020E61000001F645930F1C7EDBFEB39E97DE3CF4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19478470559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19478470559.webp', 'https://www.flickr.com/photos/zaragozaantigua/19478470559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24374, 'Parroquia paulista de Casablanca 1971', 'Imagen de la capilla que hacâ”śÂˇa las funciones, desde 1965, de iglesia parroquial de San Vicente de Paâ”śâ•‘l (Padres Paâ”śâ•‘les) en Casablanca, entre la carretera de los enlaces, y el Canal Imperial. En el momento de capturar la imagen, se estâ”śĂ­ procediendo a ensanchar la carretera de Valencia (luego Vâ”śÂˇa ibâ”śÂ®rica), lo que conllevarâ”śĂ­ la demoliciâ”śâ”‚n de edificios como el de esta parroquia (y las viviendas a su lado), y la remociâ”śâ”‚n de la Fuente de los Incrâ”śÂ®dulos, visible unas decenas de metros hacia la izquierda. La fuente fue desmontada y situada en su actual ubicaciâ”śâ”‚n, mâ”śĂ­s cerca de las esclusas de Casablanca. Ambos elementos (fuente y capilla) habâ”śÂˇan sido construidos con ocasiâ”śâ”‚n de la llegada de las aguas del Canal Imperial a Zaragoza en 1787, y esta capilla se levantâ”śâ”‚ bajo la invocaciâ”śâ”‚n (rarâ”śÂˇsima) de Nâ”¬Â¬ Sâ”¬Â¬ del Pilar, con ceremonias los dâ”śÂˇas festivos.', 1971, 1971, 1971, 'Anos 70', 'CASABLANCA', 41.62920500, -0.90765900, '0101000020E61000002A711DE38A0BEDBF66BD18CA89D04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15711548616.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15711548616.webp', 'https://www.flickr.com/photos/zaragozaantigua/15711548616/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24853, 'Calle Argualas 1973', 'Imagen del novisimo polâ”śÂˇgono residencial de Argualas, barrio de Casablanca, en el entorno de la plaza de Nâ”¬Â¬ Sâ”¬Â¬ de las Nieves. La captura se ha realizado en el cruce de la calle Argualas, con la de Brazato. Al fondo, la calle de Riglos. Tras la supresiâ”śâ”‚n en 1971 de la lâ”śÂˇnea 15 del tranvâ”śÂˇa "Casablanca", la lâ”śÂˇnea 30 del autobâ”śâ•‘s urbano fue la designada para dar servicio a este barrio de la periferia, sobre todo a esta nueva zona, en la margen derecha del Canal Imperial. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62635400, -0.91242000, '0101000020E610000018EC866D8B32EDBF01DC2C5E2CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30155372721.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30155372721.webp', 'https://www.flickr.com/photos/zaragozaantigua/30155372721/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24982, 'Depâ”śâ”‚sitos de Casablanca c.1990', 'Foto: Rafael Margalâ”śÂ®. Vista aâ”śÂ®rea de los depâ”śâ”‚sitos de agua de Casablanca, junto al Canal Imperial. Estas instalaciones fueron construidas en 1912 como principal reserva de agua potable de la ciudad. Entre 2006 y 2009, el recinto se reconvirtiâ”śâ”‚ en espacio lâ”śâ•‘dico, con un servicio de cafeterâ”śÂˇa inaugurado en 2011, luego cerrado y vuelto a licitar en 2015. Forma parte del Parque del Canal, concebido en el Plan de Acompaâ”śâ–’amiento de la Expo 2008. Cuenta con un lago y un gâ”śÂ®iser artificiales. Los actuales depâ”śâ”‚sitos se encuentran en la Vâ”śÂˇa Hispanidad. Fuente visual: www.facebook.com/photo.php?fbid=1711734895716876&set=...', 1990, 1990, 1990, 'Anos 90', 'CASABLANCA', 41.63508800, -0.91828300, '0101000020E6100000EA20AF079362EDBF810A47904AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24617860556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24617860556.webp', 'https://www.flickr.com/photos/zaragozaantigua/24617860556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25140, 'Seminario Conciliar 1945', 'Sello sin valor postal para recaudar fondos destinados a la construcciâ”śâ”‚n del "Nuevo Seminario Conciliar de Casablanca" en 1945. â”śĂ«ste fue el aâ”śâ–’o de la colocaciâ”śâ”‚n de su primera piedra, siendo inaugurado en 1952, segâ”śâ•‘n proyecto de Santiago Lagunas, Casimiro Lanaja y Manuel Martâ”śÂˇnez de Ubago, de formas historicistas neorromâ”śĂ­nicas y neogâ”śâ”‚ticas. La fachada principal, cuyo torreâ”śâ”‚n de acceso no se terminâ”śâ”‚ segâ”śâ•‘n lo previsto, se halla en las actuales traseras del edificio remodelado en 2008 para dependencias del Ayuntamiento, con acceso por Vâ”śÂˇa de la Hispanidad 20. Fuente visual: www.delcampe.net', 1945, 1945, 1945, 'Anos 40', 'CASABLANCA', 41.63542600, -0.91046000, '0101000020E6100000FC1D8A027D22EDBF9983A0A355D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22613192604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22613192604.webp', 'https://www.flickr.com/photos/zaragozaantigua/22613192604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25614, 'Vista legionaria 1973', 'A la entrada del Parque de Atracciones hay un monumento a los muertos propios del oximorâ”śâ”‚nico "Tercio de Extranjeros", o "Legiâ”śâ”‚n Espaâ”śâ–’ola", cuyo gran atractivo son unas vistas singulares de la ciudad, como la presente. De derecha a izquierda, y articulados por el paseo de Isabel la Catâ”śâ”‚lica: la Residencia Sanitaria "Josâ”śÂ® Antonio", el Colegio de Huâ”śÂ®rfanos de Magisterio, y el complejo de rascacielos de la "Residencial Isabel la Catâ”śâ”‚lica". Ya en la Vâ”śÂˇa Ibâ”śÂ®rica, el enorme complejo del Hospital Militar y las viviendas militares del otro lado; el Centro Regional de Estudios Teolâ”śâ”‚gicos de Aragâ”śâ”‚n; el reciente y privado Colegio Montearagâ”śâ”‚n; y el no menos reciente monasterio Cisterciense de Santa Lucâ”śÂˇa, aquâ”śÂˇ emigrado desde la plaza de Santo Domingo. A los pies de todo esto, el râ”śÂˇo Huerva fluye calladamente. En la mâ”śĂ­s despejada margen derecha, los viveros municipales. Fuente visual: Foto Monge, Diario "Amanecer", 24/01/1973.', 1973, 1973, 1973, 'Anos 70', 'CASABLANCA', 41.62928500, -0.90337800, '0101000020E6100000E0A0BDFA78E8ECBF836E2F698CD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19375162676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19375162676.webp', 'https://www.flickr.com/photos/zaragozaantigua/19375162676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
